#include <omp.h>
#include <stdlib.h>

#include "common.h"

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset) {
    int i, j, tx;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            shadow[i][tx] = m[(offset + i) * matrix_dim + (offset + tx)];
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++) {
                shadow[tx][i] -= shadow[tx][j] * shadow[j][i];
            }
            shadow[tx][i] /= shadow[i][i];
        }

        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++) {
                shadow[i + 1][tx] -= shadow[i + 1][j] * shadow[j][tx];
            }
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            m[(offset + i) * matrix_dim + (offset + tx)] = shadow[i][tx];
        }
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int bidx) {
    int i, j, r, c;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int col_base = offset + (bidx + 1) * BLOCK_SIZE;
    int row_base = offset + (bidx + 1) * BLOCK_SIZE;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[(offset + i) * matrix_dim + (offset + j)];
            peri_row[i][j] = m[(offset + i) * matrix_dim + (col_base + j)];
            peri_col[i][j] = m[(row_base + i) * matrix_dim + (offset + j)];
        }
    }

    for (c = 0; c < BLOCK_SIZE; c++) {
        for (r = 1; r < BLOCK_SIZE; r++) {
            for (j = 0; j < r; j++) {
                peri_row[r][c] -= dia[r][j] * peri_row[j][c];
            }
        }
    }

    for (r = 0; r < BLOCK_SIZE; r++) {
        for (c = 0; c < BLOCK_SIZE; c++) {
            for (j = 0; j < c; j++) {
                peri_col[r][c] -= peri_col[r][j] * dia[j][c];
            }
            peri_col[r][c] /= dia[c][c];
        }
    }

    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + i) * matrix_dim + (col_base + j)] = peri_row[i][j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[(row_base + i) * matrix_dim + (offset + j)] = peri_col[i][j];
        }
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int by, int bx) {
    int i, r, c;
    float sum;
    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    for (r = 0; r < BLOCK_SIZE; r++) {
        for (c = 0; c < BLOCK_SIZE; c++) {
            sum = 0.0f;
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum += m[(global_row_id + r) * matrix_dim + (offset + i)] *
                       m[(offset + i) * matrix_dim + (global_col_id + c)];
            }
            m[(global_row_id + r) * matrix_dim + (global_col_id + c)] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i = 0;

    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int chunks = (matrix_dim - i) / BLOCK_SIZE;

        lud_diagonal_omp(m, matrix_dim, i);

#pragma omp parallel for schedule(static)
        for (int bx = 0; bx < chunks - 1; bx++) {
            lud_perimeter_block_omp(m, matrix_dim, i, bx);
        }

#pragma omp parallel for collapse(2) schedule(static)
        for (int by = 0; by < chunks - 1; by++) {
            for (int bx = 0; bx < chunks - 1; bx++) {
                lud_internal_block_omp(m, matrix_dim, i, by, bx);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
